    let skinMatrix = in.weights.x * jointMatrices[in.joints.x]
                   + in.weights.y * jointMatrices[in.joints.y]
                   + in.weights.z * jointMatrices[in.joints.z]
                   + in.weights.w * jointMatrices[in.joints.w];

